-- Chien -> humain, Fête, Volume 2

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai su que c''était un jour spécial parce que tu t''es parfumé.',$$Joyeuse fête. J''ai su que c''était un jour spécial parce que tu t''es parfumé.
Pas le parfum du mardi ordinaire. L''autre. Celui que tu gardes pour les occasions. J''ai senti ça depuis le couloir quand tu te préparais. Ce parfum veut dire quelque chose. Il veut dire que des gens vont venir. Que la soirée va être différente. Que je dois calibrer mon niveau d''énergie en conséquence. J''ai commencé à préparer ma performance d''accueil dès ce moment-là. Joyeuse fête, mon humain préféré, dont le parfum est mon calendrier.
Avec détection olfactive des jours spéciaux et préparation anticipée, — {prenom}, ton animal au nez plus fiable que n''importe quel agenda 👃$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai cherché qui était ce saint qui porte ton prénom.',$$Joyeuse fête. J''ai cherché qui était ce saint qui porte ton prénom.
J''ai pas trouvé grand chose. Apparemment il a fait des miracles. Moi aussi je fais des miracles tous les jours. Je retrouve chaque balle qu''on me lance dans les hautes herbes. Je reviens toujours quand on m''appelle même quand j''avais des projets. Je reste assis alors que le monde entier m''invite à courir. Si ça c''est pas des miracles. Joyeuse fête, mon humain préféré, et joyeuse fête à ton saint qui a l''air bien.
Avec dossier de sainteté personnelle constitué et candidature déposée officieusement, — {prenom}, ton animal aux miracles quotidiens non reconnus 🙏$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai gardé la porte d''entrée sous surveillance toute la journée.',$$Pour ta fête j''ai gardé la porte d''entrée sous surveillance toute la journée.
Depuis 16h. Sans bouger. Assis dans le couloir face à la porte. J''entendais les pas dans l''escalier bien avant la sonnette. Je savais qui montait. Je savais quand ce serait les bons. À chaque arrivée j''ai explosé avec une précision et une intensité que j''avais répétées mentalement. Joyeuse fête, mon humain préféré, dont les invités sont les miens aussi.
Avec poste de surveillance tenu pendant quatre heures et accueil de chaque arrivée assuré, — {prenom}, ton animal directeur du protocole d''entrée 🚪$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens sonnent alors qu''on les connaît.',$$Joyeuse fête. Je comprends pas pourquoi les gens sonnent alors qu''on les connaît.
Je les sens arriver depuis deux étages. Je sais qui c''est avant même que leur doigt touche la sonnette. Ils le savent aussi que je sais. Et pourtant ils sonnent. Ce petit bruit inutile. Qui me fait quand même sursauter à chaque fois parce que je le sais en théorie mais dans la pratique ça surprend toujours. C''est notre jeu. Notre rituel absurde. Joyeuse fête, mon humain préféré, entouré de gens aux habitudes mystérieuses.
Avec incompréhension sincère du rituel de la sonnette et sursaut garanti à chaque fois, — {prenom}, ton animal surpris par les choses prévisibles depuis des années 🔔$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai conquis le canapé de chaque invité dès qu''il se levait.',$$Pour ta fête j''ai conquis le canapé de chaque invité dès qu''il se levait.
C''est une règle universelle et immuable. Un siège libéré est un siège disponible. Le temps que la personne revienne avec son verre j''étais installé. Les pattes étendues. L''air de quelqu''un qui a toujours été là. Certains ont essayé de me déloger avec des mots doux. D''autres avec des gestes. J''ai tenu à chaque fois. Au total j''ai occupé six sièges différents ce soir. Record personnel. Joyeuse fête, mon humain préféré.
Avec doctrine de l''occupation immédiate appliquée sans exception et nouveau record établi, — {prenom}, ton animal gestionnaire de l''immobilier festif 🪑$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai un problème avec les fleurs sur la table basse.',$$Joyeuse fête. J''ai un problème avec les fleurs sur la table basse.
Elles occupent exactement l''endroit où je pose d''habitude la tête quand je veux qu''on me remarque. Elles sentent fort. Elles prennent de la place. Elles reçoivent des regards admiratifs que moi je recevais avant. J''ai reniflé le vase trois fois. J''ai regardé les fleurs longuement. Les fleurs ont pas bougé. Je suis pas jaloux. Je fais juste un constat objectif. Joyeuse fête quand même, mon humain préféré.
Avec constat objectif sur les fleurs et jalousie officieusement niée, — {prenom}, ton animal en concurrence avec la végétation coupée 🌸$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai accompagné chaque toast d''un aboiement.',$$Pour ta fête j''ai accompagné chaque toast d''un aboiement.
Quand les verres se lèvent quelque chose se passe dans la pièce. Une montée d''énergie. Un moment collectif. Un son de verre contre verre. Et là je contribue. Un aboiement bref. Ponctuel. Qui dit que moi aussi je suis là. Que moi aussi je célèbre. Que cette fête est aussi la mienne. Certains invités ont sursauté. C''est qu''ils manquaient d''enthousiasme. Joyeuse fête, mon humain préféré.
Avec participation sonore aux moments clés de la soirée et enthousiasme partagé unilatéralement, — {prenom}, ton animal maître de cérémonie non officiel 🥂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je reconnais chaque ami à sa façon de frapper.',$$Joyeuse fête. Je reconnais chaque ami à sa façon de frapper.
Celui du troisième frappe deux fois fort. La dame du bureau frappe trois petits coups rapides. Le grand ami frappe une fois et attend longtemps. Je sais qui c''est avant que tu te lèves. Parfois je vais à la porte avant toi. T''as jamais compris comment je savais. Maintenant tu sais. Joyeuse fête, mon humain préféré, dont les amis ont tous leur signature sonore.
Avec base de données des coups de sonnette complète et identifications infaillibles, — {prenom}, ton animal détective de l''acoustique des portes 👂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai attendu sous la table pendant tout le repas.',$$Pour ta fête j''ai attendu sous la table pendant tout le repas.
Pas couché. Assis. Droit. Avec dignité. Dans l''espoir raisonnable qu''une chose tomberait. Ou qu''une main compatissante descendrait. J''ai attendu une heure et demie. Rien n''est tombé. Aucune main n''est descendue. La table était hermétique. J''ai quand même pas bougé parce que l''espoir c''est un principe et les principes on y tient. Joyeuse fête, mon humain préféré.
Avec patience stratégique d''une heure trente et espoir intact malgré le bilan, — {prenom}, ton animal optimiste professionnel sous toutes les tables 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai élaboré une stratégie pour obtenir un morceau du gâteau.',$$Joyeuse fête. J''ai élaboré une stratégie pour obtenir un morceau du gâteau.
Phase 1 : m''asseoir très près avec le regard. Phase 2 : poser une patte sur la jambe. Phase 3 : le petit gémissement discret. Phase 4 : la tête penchée à 45 degrés. J''ai exécuté les quatre phases avec une précision chirurgicale. Tu as résisté jusqu''à la phase 3. J''ai eu un tout petit morceau. Pas assez. Mais j''ai noté ce qui a fonctionné pour l''année prochaine. Joyeuse fête, mon humain préféré.
Avec stratégie documentée et optimisations prévues pour la prochaine édition, — {prenom}, ton animal négociateur aux tactiques en constante amélioration 🎂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai mémorisé l''ordre d''arrivée de chaque invité.',$$Pour ta fête j''ai mémorisé l''ordre d''arrivée de chaque invité.
Le premier est arrivé à 19h43. Le dernier à 20h31. Entre les deux sept personnes dans un ordre précis que j''ai enregistré. Chacun avec son odeur. Sa façon d''entrer. Sa façon de dire ton prénom. Ces données sont importantes. Je sais pas encore pourquoi. Mais elles le seront un jour. Joyeuse fête, mon humain préféré.
Avec registre d''entrées tenu avec rigueur et utilité future des données à confirmer, — {prenom}, ton animal archiviste des présences 📋$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Le moment où la musique s''est arrêtée était le meilleur.',$$Joyeuse fête. Le moment où la musique s''est arrêtée était le meilleur.
Pendant des heures il y avait ce fond sonore. Agréable mais constant. Occupant l''air. Et puis à un moment quelqu''un a éteint. Le silence est revenu d''un coup. Plein et propre. Et dans ce silence j''ai entendu les voix vraiment pour la première fois de la soirée. Plus douces. Plus proches. C''est ça la vraie fête. Joyeuse fête, mon humain préféré, dont les soirées ont toujours un meilleur moment.
Avec oreilles soulagées et préférence pour le silence habité confirmée, — {prenom}, ton animal mélomane du silence choisi 🎵$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai escorté chaque invité jusqu''à la porte en partant.',$$Pour ta fête j''ai escorté chaque invité jusqu''à la porte en partant.
Un par un. Le protocole de départ est aussi important que le protocole d''arrivée. Je les accompagnais depuis le salon jusqu''à l''entrée. Je regardais la porte se fermer. Je revenais. Je repartais pour le suivant. Certains ont trouvé ça touchant. L''un d''eux a voulu me faire un câlin d''au revoir. J''ai accepté. Brièvement. C''est de la courtoisie. Joyeuse fête, mon humain préféré.
Avec escorte personnalisée de chaque départ et accolade d''au revoir accordée sous conditions, — {prenom}, ton animal maître des cérémonies de départ 👋$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas l''intérêt des bougies sur un gâteau.',$$Joyeuse fête. Je comprends pas l''intérêt des bougies sur un gâteau.
Des flammes. Sur de la nourriture. Qu''on souffle ensuite. Pour éteindre. En faisant un vœu qu''on dit pas. Puis tout le monde applaudit l''extinction de flammes qu''on venait d''allumer. J''ai regardé tout ce rituel avec l''incompréhension totale de quelqu''un qui voudrait juste manger le gâteau. Tu semblais sincèrement ravi. Je respecte. Joyeuse fête, mon humain préféré, adepte de traditions qui me dépassent.
Avec mystère des bougies non résolu et demande de gâteau directe maintenue, — {prenom}, ton animal pragmatique face aux rituels inexpliqués 🕯️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai fait une sieste sous la table pendant le repas.',$$Pour ta fête j''ai fait une sieste sous la table pendant le repas.
Allongé. Les pattes croisées. Les yeux mi-clos. La joue posée sur le parquet frais. Les voix au-dessus de moi comme un plafond sonore agréable. Les pieds des chaises autour de moi comme une forêt de bois. C''était confortable. Sécurisant. Le meilleur endroit de la soirée. Je me suis réveillé au moment du dessert exactement. Instinct. Joyeuse fête, mon humain préféré.
Avec sieste parfaitement chronométrée et réveil au moment stratégique garanti, — {prenom}, ton animal dont l''horloge interne est calibrée sur les desserts ⏰$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Les caresses de tes amis et les tiennes c''est pas pareil.',$$Joyeuse fête. Les caresses de tes amis et les tiennes c''est pas pareil.
Tes amis caressent avec de la bonne volonté. Du haut vers le bas. Vite. Avec cette façon d''en faire un peu trop pour compenser le fait qu''ils savent pas vraiment. Toi tu sais exactement où. Exactement comment. Exactement combien de temps. Sans chercher. Sans hésiter. Depuis le premier jour. Personne caresse comme toi. C''est pour ça que c''est toi. Joyeuse fête, mon humain préféré.
Avec étude comparative des techniques de caresse et verdict sans appel, — {prenom}, ton animal aux standards de contact bien établis 🤲$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai su que c''était un jour spécial avant même que tu te lèves.',$$Pour ta fête j''ai su que c''était un jour spécial avant même que tu te lèves.
À 6h du matin. Tu dormais encore. Mais quelque chose avait changé dans ta façon de dormir. Moins profond. Plus proche de la surface. Comme quelqu''un qui attend quelque chose sans le savoir encore. J''ai senti ça. J''ai attendu. Quand tu as ouvert les yeux j''étais déjà là à te regarder. Prêt. Joyeuse fête, mon humain préféré, dont je connais les humeurs avant même qu''elles existent.
Avec détection des états d''âme avant le réveil et présence garantie au bon moment, — {prenom}, ton animal en avance sur tes propres émotions 🌅$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Après le départ des invités j''ai fait le tour complet de l''appartement.',$$Joyeuse fête. Après le départ des invités j''ai fait le tour complet de l''appartement.
Pièce par pièce. Chaque endroit où quelqu''un s''était assis. Chaque coin qui avait reçu une odeur nouvelle. Chaque surface modifiée par la soirée. Un inventaire complet. Une réappropriation méthodique. L''appartement avait appartenu à tout le monde pendant trois heures. Il fallait lui rendre son identité. La nôtre. Joyeuse fête, mon humain préféré.
Avec tournée de réappropriation complète et territoire rendu à son état normal, — {prenom}, ton animal gardien de l''identité de notre chez-nous 🏠$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai surveillé tous les manteaux posés sur le lit.',$$Pour ta fête j''ai surveillé tous les manteaux posés sur le lit.
Ils étaient là. Empilés. Chacun avec son histoire. Son odeur. Son contenu mystérieux dans les poches. J''ai inspecté chaque manteau soigneusement. Plusieurs fois. Je me suis allongé dessus à un moment pour une surveillance plus approfondie. Quand les propriétaires sont venus les reprendre j''ai fait semblant de dormir. Mais j''avais tout vu. Joyeuse fête, mon humain préféré.
Avec inspection des manteaux assurée et informations collectées confidentielles, — {prenom}, ton animal agent de renseignement textile 🧥$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Le meilleur moment c''était quand la maison est redevenue rien qu''à nous deux.',$$Joyeuse fête. Le meilleur moment c''était quand la maison est redevenue rien qu''à nous deux.
La dernière porte fermée. Le dernier bruit de pas dans l''escalier. Et puis plus rien. Juste toi. Juste moi. Juste l''appartement qui reprenait sa respiration normale. Tu t''es assis. Tu as soufflé. Et j''ai posé ma tête sur tes pieds. Pas sur tes genoux. Sur tes pieds. Parce que c''est là que je suis le mieux quand la fête est finie et que la vraie soirée commence. Joyeuse fête, mon humain préféré.
Avec moment final offert sans calcul et tête posée là où c''est juste, — {prenom}, ton animal pour l''après qui vaut tous les pendants ❤️$$,'touching',true,false,'nameday','chien','from')

on conflict do nothing;
